content.problemStatement:
What will be the output of the following C++ program?

```cpp
#include 
using namespace std;


void modifyNumber(int num) {
    num = num + 5;  // Modify the value of num inside the function
    cout << "Value inside function: " << num << endl;
}

int main() {
    int number = 10;
    modifyNumber(number);  // Call the function with 'number'
    cout << "Value outside function: " << number << endl;  
    return 0;
}
```

